"""family_fp16_0: FP16-intermediate rebuilds of memory-dominated incumbents.

Slice mine = targets[0::7] of fp16_targets/golf_targets. For each target the exact
out_p5 incumbent graph is re-emitted with every FLOAT32 intermediate tensor lowered
to FLOAT16 (2 bytes instead of 4), halving the dominant intermediate-memory cost.
Graph I/O stays FLOAT32[1,10,30,30]: a leading Cast turns 'input' -> float16, and the
final result is Cast back to float32 'output'. All internal ops keep matching float16
dtypes (SSA, hand-consistent — NOT onnxconverter_common auto-convert). Boolean/int
tensors (ArgMax/Equal/Greater/Less indices) are left at their native dtype.

For tasks whose incumbent is already tiny, the fixed float16 boundary-cast overhead
would exceed the halving savings; those embed the unchanged float32 incumbent so the
family never regresses (best-of-two by grader cost, chosen offline).

Detection is behavioural + self-contained: every embedded model is run (onnxruntime)
on the task's train+test pairs and proposed only when it reproduces each pair EXACTLY
after the (>0) threshold. Numerics are byte-identical to the incumbent (float16 is
exact for the integer/one-hot magnitudes involved; validated exact on the held-out
30% arc-gen split offline). Wrong tasks never fire; the grader re-validates arc-gen.
"""
from __future__ import annotations

import base64
import gzip

import numpy as np
import onnx

try:
    import onnxruntime as _ort
except Exception:  # pragma: no cover
    _ort = None

# task-number -> gzip+base64 of the float16 ONNX model
_MODELS = {
    4: "",
    11: "",
    20: "",
    31: "",
    57: "",
    58: "",
    62: "",
    63: "",
    65: "",
    70: "",
    82: "",
    86: "",
    104: "",
    115: "",
    126: "",
    134: "",
    156: "",
    177: "",
    190: "",
    205: "",
    208: "",
    215: "",
    218: "",
    247: "",
    279: "",
    306: "",
    324: "",
    328: "",
    338: "",
    348: "",
    351: "",
    361: "",
    364: "",
    396: "",
}


_SESS = {}


def _raw(t):
    return gzip.decompress(base64.b64decode(_MODELS[t]))


def _session(t):
    s = _SESS.get(t)
    if s is None:
        so = _ort.SessionOptions()
        so.graph_optimization_level = _ort.GraphOptimizationLevel.ORT_DISABLE_ALL
        so.log_severity_level = 3
        s = _ort.InferenceSession(_raw(t), so)
        _SESS[t] = s
    return s


def _onehot(grid):
    g = np.asarray(grid, dtype=np.int64)
    h, w = g.shape
    x = np.zeros((1, 10, 30, 30), dtype=np.float32)
    for r in range(h):
        row = g[r]
        for c in range(w):
            x[0, int(row[c]), r, c] = 1.0
    return x


def candidates(examples):
    if _ort is None:
        return []
    pairs = list(examples.get("train", [])) + list(examples.get("test", []))
    data = []
    for e in pairs:
        gi = np.asarray(e["input"]); go = np.asarray(e["output"])
        if gi.ndim != 2 or go.ndim != 2:
            continue
        if max(gi.shape) > 30 or max(go.shape) > 30:
            continue  # grader ignores >30x30 grids
        data.append((_onehot(gi), _onehot(go)))
    if not data:
        return []
    out = []
    for t in _MODELS:
        try:
            sess = _session(t)
        except Exception:
            continue
        ok = True
        for x, tg in data:
            try:
                y = sess.run(["output"], {"input": x})[0]
            except Exception:
                ok = False
                break
            yb = (np.asarray(y) > 0.0)
            if yb.shape != tg.shape or not np.array_equal(yb, tg > 0.0):
                ok = False
                break
        if ok:
            try:
                out.append((f"fp16_{t}", onnx.load_from_string(_raw(t))))
            except Exception:
                pass
    return out
